func:
const modo = global.get('modo_fuente') || 'simulado';

let t = global.get('tiempo_sim') || 0;

// === MODO REAL ===
if (modo === 'real') {
    const datosReales = global.get('datos_reales');

    if (!datosReales || datosReales.length === 0) {
        node.warn('Datos reales no disponibles');
        return null;
    }

    const PASO_DEMO = 6;
    t = t + PASO_DEMO;

    if (t >= datosReales.length) {
        t = datosReales.length - 1;
        global.set('csv_completado', true);
    }
    global.set('tiempo_sim', t);

    const registro = datosReales[t];
    const temp = parseFloat(registro.temperatura);
    const hum = parseFloat(registro.humedad);

    const horasReales = Math.floor((t * 5) / 60);
    const dia = horasReales / 24;

    global.set('tiempo_horas_csv', horasReales);
    global.set('tiempo_dia_csv', dia);

    const rssi = Math.round(-95 - Math.random() * 15);
    const snr = Math.round((5 + Math.random() * 5) * 10) / 10;

    msg.payload = {
        temperatura: temp,
        humedad: hum,
        tiempo_horas: horasReales,
        tiempo_dias: Math.round(dia * 100) / 100,
        fase: registro.fase || '',
        alerta: registro.alerta || '',
        timestamp_real: registro.timestamp,
        rssi: rssi,
        snr: snr,
        modo: 'real',
        timestamp: Date.now()
    };

    return msg;
}

// === MODO SIMULADO ===
t = t + 1;
if (t > 168) {
    t = 168;
}
global.set('tiempo_sim', t);

const dia = t / 24;

let temp;
if (dia < 1) {
    temp = 25 + (dia * 5);
} else if (dia < 2) {
    temp = 30 + ((dia - 1) * 10);
} else if (dia < 3) {
    temp = 40 + ((dia - 2) * 8);
} else if (dia < 5) {
    temp = 48 + Math.sin((dia - 3) * 2) * 2;
} else {
    temp = 48 - ((dia - 5) * 4);
}
temp = temp + (Math.random() * 2 - 1);

const eventoTemp = Math.random();
if (eventoTemp < 0.025 && dia >= 2 && dia < 6) {
    temp = 56 + Math.random() * 4;
} else if (eventoTemp < 0.05 && dia >= 2 && dia < 6) {
    temp = 35 + Math.random() * 4;
}
temp = Math.round(temp * 10) / 10;

let hum = 80 + Math.sin(t / 10) * 3 + (Math.random() * 4 - 2);
const eventoHum = Math.random();
if (eventoHum < 0.02) {
    hum = 91 + Math.random() * 4;
} else if (eventoHum < 0.04) {
    hum = 55 + Math.random() * 4;
}
hum = Math.round(hum * 10) / 10;

const rssi = Math.round(-95 - Math.random() * 15);
const snr = Math.round((5 + Math.random() * 5) * 10) / 10;

msg.payload = {
    temperatura: temp,
    humedad: hum,
    tiempo_horas: t,
    tiempo_dias: Math.round(dia * 100) / 100,
    fase: '',
    alerta: '',
    rssi: rssi,
    snr: snr,
    modo: 'simulado',
    timestamp: Date.now()
};

return msg;

// Solo guardar si hay un proceso activo
if (global.get("proceso_activo") !== true) {
    return null;
}

const datos = msg.payload;
const lote_id = global.get("lote_id") || "lote_sin_id";
const modo = global.get('modo_fuente') || 'simulado';

// Construir el objeto de campos (fields)
const fields = {
    temperatura: datos.temperatura,
    humedad: datos.humedad,
    tiempo_horas: datos.tiempo_horas,
    rssi: datos.rssi,
    snr: datos.snr
};

// === CLAVE: si es modo real, usar el timestamp del CSV ===
if (modo === 'real' && datos.timestamp_real) {
    // Convertir el timestamp ISO 8601 del CSV a Date object
    fields.time = new Date(datos.timestamp_real);
}
// Si es modo simulado, NO añadimos 'time' → InfluxDB usa la hora actual (correcto)

msg.payload = [
    fields,
    {
        lote_id: lote_id,
        sensor: "nodo_01",
        modo: modo
    }
];

return msg;

global.set('datos_reales', msg.payload);
global.set('datos_reales_total', msg.payload.length);
global.set('csv_completado', false);
global.set('tiempo_horas_csv', 0);

node.status({ fill: 'green', shape: 'dot', text: 'Cargados: ' + msg.payload.length + ' registros' });

return null;

if (msg.topic === "usuario") {
    global.set("temp_usuario", msg.payload);
    return null;
}

if (msg.topic === "password") {
    global.set("temp_password", msg.payload);
    return null;
}

if (msg.topic === "login_request") {
    const usuario = global.get("temp_usuario") || "";
    const password = global.get("temp_password") || "";

    const usuarios = {
        "agricultor": { pass: "cacao123", rol: "agricultor" },
        "tecnico":    { pass: "tecnico123", rol: "tecnico" },
        "jefe":       { pass: "jefe123", rol: "jefe" },
        "admin":      { pass: "admin123", rol: "admin" }
    };

    if (usuarios[usuario] && usuarios[usuario].pass === password) {
        global.set("perfil_activo", usuarios[usuario].rol);
        global.set("usuario_activo", usuario);

        msg.payload = {
            tipo: "exito",
            rol: usuarios[usuario].rol
        };
        return [msg, null];
    } else {
        msg.payload = "Usuario o contraseña incorrectos";
        return [null, msg];
    }
}

return null;

const rol = msg.payload && msg.payload.rol;
let tabDestino = "Login";

switch (rol) {
    case "agricultor":
        tabDestino = "Agricultor - Lote Actual";
        break;
    case "tecnico":
        tabDestino = "Tecnico - LoRa";
        break;
    case "jefe":
        tabDestino = "Jefe - Monitoreo";
        break;
    case "admin":
        tabDestino = "Admin - Inicio";
        break;
}

msg.payload = { tab: tabDestino };
return msg;

if (msg.payload !== "connect" && msg.payload !== "change") {
    return null;
}

global.set("temp_usuario", "");
global.set("temp_password", "");

return [
    { payload: "" },
    { payload: "" }
];

// Limpiar el contexto del usuario
global.set("perfil_activo", null);
global.set("usuario_activo", null);
global.set("temp_usuario", "");
global.set("temp_password", "");

// Salida 1: redirigir al login
const msgRedirect = { payload: { tab: "Login" } };

// Salida 2: limpiar campos del login (igualito que cuando arrancas)
const msgLimpiar = { payload: "" };

return [msgRedirect, msgLimpiar];

if (msg.topic === 'modo_fuente' && msg.payload) {
    global.set('modo_fuente', msg.payload);
    node.status({ fill: 'blue', shape: 'dot', text: 'Modo: ' + msg.payload });
}
return null;

if (msg.topic === "ph_inicial") {
    if (global.get("proceso_activo") !== true) {
        global.set("ph_inicial_temp", parseFloat(msg.payload));
    }
    return null;
}

if (msg.topic === "iniciar_lote") {
    if (global.get("proceso_activo") === true) {
        msg.payload = "Ya hay un proceso en curso. Debe finalizarlo antes de iniciar uno nuevo.";
        return [null, msg];
    }

    const pH = global.get("ph_inicial_temp");

    if (!pH || isNaN(pH)) {
        msg.payload = "Debe ingresar el pH inicial antes de iniciar";
        return [null, msg];
    }

    const modo = global.get('modo_fuente') || 'simulado';
    const prefijoLote = (modo === 'real') ? 'lote_real_' : 'lote_sim_';
    const lote_id = prefijoLote + new Date().toISOString().replace(/[:.]/g, "-").substring(0, 19);

    global.set("lote_id", lote_id);
    global.set("ph_inicial", pH);
    global.set("hora_inicio", Date.now());
    global.set("proceso_activo", true);
    global.set("dia_actual", -1);
    global.set("cierre_automatico", false);
    global.set("temp_max_lote", null);
    global.set("temp_min_lote", null);
    global.set("paquetes_totales", 0);
    global.set("paquetes_perdidos", 0);
    global.set("log_alarmas", []);

    // === IMPORTANTE: RESETEAR CONTADOR DEL SIMULADOR ===
    global.set("tiempo_sim", 0);
    global.set("csv_completado", false);
    global.set("tiempo_horas_csv", 0);
    global.set("tiempo_dia_csv", 0);

    msg.payload = "PROCESO ACTIVO";
    return [msg, null];
}

return null;

if (global.get("proceso_activo") === true && global.get("cierre_automatico") !== true) {
    global.set("ultimo_dato_sim", msg.payload);
    msg.payload = msg.payload.temperatura;
    return msg;
}
return null;

if (global.get("proceso_activo") === true && global.get("cierre_automatico") !== true) {
    msg.payload = msg.payload.humedad;
    return msg;
}
return null;

if (global.get("proceso_activo") !== true) {
    return [{ payload: "Sin proceso activo" }, null, { payload: "" }];
}

const modo = global.get('modo_fuente') || 'simulado';

// === MODO REAL: usar timestamps del CSV ===
if (modo === 'real') {
    const horasTotales = global.get('tiempo_horas_csv') || 0;
    const dias = Math.floor(horasTotales / 24);
    const horas = horasTotales - (dias * 24);
    const csvCompletado = global.get('csv_completado') === true;

    // Cierre automático cuando se agoten los datos del CSV
    if (csvCompletado && global.get("cierre_automatico") !== true) {
        global.set("cierre_automatico", true);
        global.set("hora_cierre_auto", Date.now());

        const msgTiempo = { payload: dias + " días, " + horas + " horas (CIERRE AUTOMÁTICO - FIN DE DATOS)" };
        const msgAviso = { 
            topic: "PROCESO FINALIZADO POR FIN DE DATOS REALES",
            payload: "Se han agotado los " + (global.get('datos_reales_total') || 1805) + " registros del experimento real. Ingrese el pH final para continuar."
        };
        const msgAvisoPermanente = { payload: "⚠ Coloque el pH Final para finalizar el proceso" };

        return [msgTiempo, msgAviso, msgAvisoPermanente];
    }

    if (global.get("cierre_automatico") === true) {
        return [
            { payload: dias + " días, " + horas + " horas (CIERRE AUTOMÁTICO - FIN DE DATOS)" },
            null,
            { payload: "⚠ Coloque el pH Final para finalizar el proceso" }
        ];
    }

    // Verificar avisos de volteo
    const diaAnterior = global.get("dia_actual");
    global.set("dia_actual", dias);

    if (dias !== diaAnterior && (dias === 2 || dias === 4)) {
        global.set("aviso_volteo", true);
    }

    return [
        { payload: dias + " días, " + horas + " horas" },
        null,
        { payload: "" }
    ];
}

// === MODO SIMULADO (comportamiento original) ===
const horaInicio = global.get("hora_inicio");
if (!horaInicio) {
    return [{ payload: "Sin proceso activo" }, null, { payload: "" }];
}

const segundosReales = (Date.now() - horaInicio) / 1000;
const horasTotales = Math.floor(segundosReales / 2);
const dias = Math.floor(horasTotales / 24);
const horas = horasTotales - (dias * 24);

if (dias >= 7 && global.get("cierre_automatico") !== true) {
    global.set("cierre_automatico", true);
    global.set("hora_cierre_auto", Date.now());

    const msgTiempo = { payload: "7 días, 0 horas (CIERRE AUTOMÁTICO)" };
    const msgAviso = { 
        topic: "PROCESO FINALIZADO POR TIEMPO MÁXIMO",
        payload: "El proceso ha alcanzado el tiempo máximo de 7 días. Debe ingresar el pH final para continuar."
    };
    const msgAvisoPermanente = { payload: "⚠ Coloque el pH Final para finalizar el proceso" };

    return [msgTiempo, msgAviso, msgAvisoPermanente];
}

if (global.get("cierre_automatico") === true) {
    return [
        { payload: "7 días, 0 horas (CIERRE AUTOMÁTICO)" },
        null,
        { payload: "⚠ Coloque el pH Final para finalizar el proceso" }
    ];
}

const diaAnterior = global.get("dia_actual");
global.set("dia_actual", dias);

if (dias !== diaAnterior && (dias === 2 || dias === 4)) {
    global.set("aviso_volteo", true);
}

return [
    { payload: dias + " días, " + horas + " horas" },
    null,
    { payload: "" }
];

if (global.get("aviso_volteo")) {
    global.set("aviso_volteo", false);

    const dias = global.get("dia_actual");
    msg.payload = "RECORDATORIO: Realizar volteo de la masa (Día " + dias + ")";
    return msg;
}

return null;

if (msg.topic === "ph_final") {
    global.set("ph_final_temp", parseFloat(msg.payload));
    return null;
}

if (msg.topic === "finalizar_lote") {
    if (!global.get("proceso_activo")) {
        msg.payload = "No hay un proceso activo para finalizar";
        return [null, msg];
    }

    const cierreAuto = global.get("cierre_automatico") === true;

    if (!cierreAuto) {
        const dias = global.get("dia_actual") || 0;
        if (dias < 5) {
            msg.payload = "El proceso debe durar al menos 5 días. Día actual: " + dias;
            return [null, msg];
        }
    }

    const phFinal = global.get("ph_final_temp");
    if (!phFinal || isNaN(phFinal)) {
        msg.payload = "Debe ingresar el pH final antes de finalizar";
        return [null, msg];
    }

    const lote_id = global.get("lote_id");
    const ph_inicial = global.get("ph_inicial");
    const hora_inicio = global.get("hora_inicio");
    const hora_fin = Date.now();
    // Factor: 2 segundos reales = 1 hora simulada
    const segundosReales = (hora_fin - hora_inicio) / 1000;
    const duracion_horas = Math.floor(segundosReales / 2);

    const loteAnteriorPrevio = global.get("lote_anterior");
    if (loteAnteriorPrevio) {
        global.set("lote_penultimo", loteAnteriorPrevio);
    }

    global.set("lote_anterior", {
        lote_id: lote_id,
        ph_inicial: ph_inicial,
        ph_final: phFinal,
        hora_inicio: hora_inicio,
        hora_fin: hora_fin,
        duracion_horas: duracion_horas,
        cierre_automatico: cierreAuto
    });

    global.set("proceso_activo", false);
    global.set("ph_inicial_temp", null);
    global.set("ph_final_temp", null);
    global.set("cierre_automatico", false);
    global.set("dia_actual", -1);

    msg.payload = "PROCESO FINALIZADO";
    return [msg, null];
}

return null;

if (msg.payload !== "connect" && msg.payload !== "change") {
    return null;
}

const procesoActivo = global.get("proceso_activo") === true;
const cierreAuto = global.get("cierre_automatico") === true;

if (procesoActivo && cierreAuto) {
    const ultimoDato = global.get("ultimo_dato_sim") || { temperatura: 0, humedad: 0 };
    const phInicial = global.get("ph_inicial") || "";

    global.set("ph_final_temp", null);

    return [
        { payload: "ESPERANDO pH FINAL" },
        { payload: ultimoDato.temperatura },
        { payload: ultimoDato.humedad },
        { payload: "7 días, 0 horas (CIERRE AUTOMÁTICO)" },
        { payload: phInicial },
        { payload: "" },
        { payload: "⚠ Coloque el pH Final para finalizar el proceso" }
    ];
} else if (procesoActivo) {
    const ultimoDato = global.get("ultimo_dato_sim") || { temperatura: 0, humedad: 0 };
    const phInicial = global.get("ph_inicial") || "";

    global.set("ph_final_temp", null);

    return [
        { payload: "PROCESO ACTIVO" },
        { payload: ultimoDato.temperatura },
        { payload: ultimoDato.humedad },
        { payload: "Calculando..." },
        { payload: phInicial },
        { payload: "" },
        { payload: "" }
    ];
} else {
    global.set("dia_actual", -1);
    global.set("ph_inicial_temp", null);
    global.set("ph_final_temp", null);
    global.set("cierre_automatico", false);

    return [
        { payload: "EN ESPERA" },
        { payload: 0 },
        { payload: 0 },
        { payload: "Sin proceso activo" },
        { payload: "" },
        { payload: "" },
        { payload: "" }
    ];
}

if (msg.payload !== "PROCESO FINALIZADO") {
    return null;
}

const loteAnterior = global.get("lote_anterior");
if (!loteAnterior) {
    return null;
}

// Construir query para obtener MAX y MIN del lote
msg.query = "SELECT MAX(temperatura) AS tmax, MIN(temperatura) AS tmin FROM datos_sensores WHERE lote_id = '" + loteAnterior.lote_id + "'";

return msg;

// msg.payload viene de Consultar Max Min Lote (resultado de la query)
const resultado = msg.payload && msg.payload.length > 0 ? msg.payload[0] : null;

const loteAnterior = global.get("lote_anterior");
if (!loteAnterior) {
    return null;
}

const tempMax = resultado && resultado.tmax !== null ? resultado.tmax : null;
const tempMin = resultado && resultado.tmin !== null ? resultado.tmin : null;

// Actualizar el lote_anterior con los valores
loteAnterior.temp_max = tempMax;
loteAnterior.temp_min = tempMin;
global.set("lote_anterior", loteAnterior);

// Formato para guardar en InfluxDB
msg.payload = [
    {
        ph_inicial: loteAnterior.ph_inicial,
        ph_final: loteAnterior.ph_final,
        duracion_horas: loteAnterior.duracion_horas,
        cierre_automatico: loteAnterior.cierre_automatico ? 1 : 0,
        temp_max: tempMax,
        temp_min: tempMin
    },
    {
        lote_id: loteAnterior.lote_id
    }
];

return msg;

if (msg.payload !== "connect" && msg.payload !== "change") {
    return null;
}
const perfil = global.get("perfil_activo");
msg.payload = perfil || "";
return msg;

if (msg.payload === "volver_admin") {
    return { payload: { tab: "Admin - Inicio" } };
}
return null;

const procesoActivo = global.get("proceso_activo") === true;
const cierreAuto = global.get("cierre_automatico") === true;

let estado, temp, hum, ultimaAct, loteId, phInicial, phFinal, tiempo;

if (procesoActivo) {
    const datos = msg.payload;

    // Estado del proceso
    if (cierreAuto) {
        estado = "ESPERANDO pH FINAL";
    } else {
        estado = "PROCESO ACTIVO";
    }

    temp = datos.temperatura.toFixed(1);
    hum = datos.humedad.toFixed(1);

    // Hora actual formateada
    const ahora = new Date();
    ultimaAct = ahora.toLocaleTimeString("es-EC", { hour: "2-digit", minute: "2-digit", second: "2-digit" });

    // Datos del lote
    loteId = global.get("lote_id") || "—";
    phInicial = global.get("ph_inicial") || "—";
    phFinal = global.get("ph_final_temp") || "Pendiente";

    // Tiempo - respeta el modo de operación
    const modo = global.get('modo_fuente') || 'simulado';
    let horasTotales;

    if (modo === 'real') {
        horasTotales = global.get('tiempo_horas_csv') || 0;
    } else {
        const horaInicio = global.get("hora_inicio") || Date.now();
        const segundosReales = (Date.now() - horaInicio) / 1000;
        horasTotales = Math.floor(segundosReales / 2);
}

const dias = Math.floor(horasTotales / 24);
const horas = horasTotales - (dias * 24);
tiempo = dias + " días, " + horas + " horas";

} else {
    estado = "EN ESPERA";
    temp = "—";
    hum = "—";
    ultimaAct = "—";
    loteId = "Sin lote activo";
    phInicial = "—";
    phFinal = "—";
    tiempo = "—";
}

return [
    { payload: estado },
    { payload: temp },
    { payload: hum },
    { payload: ultimaAct },
    { payload: loteId },
    { payload: phInicial },
    { payload: phFinal },
    { payload: tiempo }
];

if (global.get("proceso_activo") !== true) {
    return null;
}

if (global.get("cierre_automatico") === true) {
    return null;
}

const datos = msg.payload;

// Calcular el tiempo simulado del proceso
const horaInicio = global.get("hora_inicio") || Date.now();
const segundosReales = (Date.now() - horaInicio) / 1000;
const horasSim = segundosReales / 2;

// Crear timestamp simulado (cada hora simulada = 1 hora real en la gráfica)
const timestampSim = horaInicio + (horasSim * 60 * 60 * 1000);

// Formato simple: solo enviar el valor con timestamp custom
const msgTemp = {
    payload: datos.temperatura,
    timestamp: timestampSim
};

const msgHum = {
    payload: datos.humedad,
    timestamp: timestampSim
};

return [msgTemp, msgHum];

if (msg.payload === "PROCESO ACTIVO") {
    const reset = { payload: [] };
    return [reset, reset];
}

return null;

// Solo procesar si hay proceso activo
if (global.get("proceso_activo") !== true) {
    return null;
}

const datos = msg.payload;
const temp = datos.temperatura;
const hum = datos.humedad;

// Obtener log existente o crear uno nuevo
let logAlarmas = global.get("log_alarmas") || [];

// Calcular tiempo del proceso
const horaInicio = global.get("hora_inicio") || Date.now();
const segundosReales = (Date.now() - horaInicio) / 1000;
const horasTotales = Math.floor(segundosReales / 2);
const dias = Math.floor(horasTotales / 24);
const horas = horasTotales - (dias * 24);
const tiempoStr = "Día " + dias + ", " + horas + "h";

// Función para verificar si ya hay una alarma reciente del mismo tipo (evitar spam)
function alarmaReciente(tipo) {
    const ultimaAlarma = logAlarmas.find(function(a) { 
        return a.variable === tipo; 
    });
    if (!ultimaAlarma) return false;

    // Si la última alarma de este tipo fue hace menos de 12 horas simuladas, no repetir
    const tiempoUltima = ultimaAlarma.tiempo_horas;
    return (horasTotales - tiempoUltima) < 12;
}

let nuevasAlarmas = false;

// === ALARMAS DE TEMPERATURA ===
if (temp > 55) {
    if (!alarmaReciente("Temperatura ALTA")) {
        logAlarmas.unshift({
            timestamp: new Date().toLocaleString("es-EC"),
            tiempo_proceso: tiempoStr,
            tiempo_horas: horasTotales,
            variable: "Temperatura ALTA",
            valor: temp.toFixed(1) + " °C",
            umbral: "> 55 °C",
            severidad: "🔴 Crítica"
        });
        nuevasAlarmas = true;
    }
} else if (temp < 40 && dias >= 2) {
    // Solo alarmar por temperatura baja a partir del día 2 (en fase acética)
    if (!alarmaReciente("Temperatura BAJA")) {
        logAlarmas.unshift({
            timestamp: new Date().toLocaleString("es-EC"),
            tiempo_proceso: tiempoStr,
            tiempo_horas: horasTotales,
            variable: "Temperatura BAJA",
            valor: temp.toFixed(1) + " °C",
            umbral: "< 40 °C",
            severidad: "🟡 Advertencia"
        });
