function formatLote(lote) {
    const dias = Math.floor(lote.duracion_horas / 24);
    const horas = lote.duracion_horas % 24;
    return {
        lote_id: lote.lote_id,
        ph_inicial: lote.ph_inicial,
        ph_final: lote.ph_final,
        duracion: dias + "d " + horas + "h",
        duracion_horas: lote.duracion_horas,
        temp_max: lote.temp_max !== null && lote.temp_max !== undefined ? Number(lote.temp_max).toFixed(1) : "—",
        temp_min: lote.temp_min !== null && lote.temp_min !== undefined ? Number(lote.temp_min).toFixed(1) : "—",
        cierre_auto: lote.cierre_automatico === 1 ? "Sí" : "No"
    };
}

function analizarLote(lote) {
    const phFinal = parseFloat(lote.ph_final);
    const tempMax = parseFloat(lote.temp_max);
    const tempMin = parseFloat(lote.temp_min);
    const duracionHoras = lote.duracion_horas;
    const esLoteReal = (lote.lote_id || '').startsWith('lote_real_');

    // === IDEAL TEÓRICO (mismo para todos): 45-50°C ===
    // En escala experimental (~20 kg) la disipación natural impide alcanzarlo
    // pero ese ES el objetivo a largo plazo.

    let tempEsperadaMin, tempEsperadaMax, tempIdealMin, tempIdealMax, tempAceptableMin, tempAceptableMax, tempAltoMax;

    // Rangos IDEALES TEÓRICOS (siempre los mismos)
    tempIdealMin = 45;
    tempIdealMax = 50;

    if (esLoteReal) {
        // En escala experimental, lo ESPERADO es 32-40°C (por limitación física de masa)
        // No se penaliza fuerte pero tampoco se considera "óptimo biológico"
        tempEsperadaMin = 32;
        tempEsperadaMax = 40;
        tempAceptableMin = 28;
        tempAceptableMax = 44;
        tempAltoMax = 48;
    } else {
        // Escala comercial: SÍ debe alcanzar el ideal teórico
        tempEsperadaMin = 45;
        tempEsperadaMax = 50;
        tempAceptableMin = 40;
        tempAceptableMax = 52;
        tempAltoMax = 55;
    }

    let pPh = 0;
    if (phFinal >= 4.5 && phFinal <= 5.5) pPh = 25;
    else if ((phFinal >= 4.2 && phFinal < 4.5) || (phFinal > 5.5 && phFinal <= 5.8)) pPh = 20;
    else if ((phFinal >= 4.0 && phFinal < 4.2) || (phFinal > 5.8 && phFinal <= 6.0)) pPh = 13;
    else pPh = 6;

    let pDur = 0;
    if (duracionHoras >= 120 && duracionHoras <= 168) pDur = 25;
    else if ((duracionHoras >= 108 && duracionHoras < 120) || (duracionHoras > 168 && duracionHoras <= 180)) pDur = 22;
    else if (duracionHoras >= 96 && duracionHoras < 108) pDur = 17;
    else if (duracionHoras > 180 && duracionHoras <= 192) pDur = 15;
    else pDur = 6;

    let pTemp = 0;
    if (tempMax >= tempEsperadaMin && tempMax <= tempEsperadaMax) pTemp = 25;
    else if (tempMax > tempEsperadaMax && tempMax <= tempAceptableMax) pTemp = 20;
    else if (tempMax >= tempAceptableMin && tempMax < tempEsperadaMin) pTemp = 20;
    else if (tempMax > tempAceptableMax && tempMax <= tempAltoMax) pTemp = 13;
    else if (tempMax > tempAltoMax) pTemp = 8;
    else pTemp = 10;

    let pEst = 0;
    const rango = tempMax - tempMin;
    if (rango <= 12) pEst = 25;
    else if (rango <= 18) pEst = 22;
    else if (rango <= 25) pEst = 17;
    else if (rango <= 35) pEst = 12;
    else pEst = 8;

    const total = pPh + pDur + pTemp + pEst;

    let cal = '', color = '';
    if (total >= 90) { cal = 'EXCELENTE'; color = '#2E7D32'; }
    else if (total >= 70) { cal = 'BUENA'; color = '#558B2F'; }
    else if (total >= 50) { cal = 'ACEPTABLE'; color = '#F9A825'; }
    else { cal = 'REQUIERE MEJORAS'; color = '#C62828'; }

    // ¿Alcanzó el ideal teórico real (45-50°C)?
    const alcanzaIdealTeorico = (tempMax >= tempIdealMin && tempMax <= tempIdealMax);

    return {
        puntos_ph: pPh, puntos_dur: pDur, puntos_temp: pTemp, puntos_est: pEst,
        puntaje: total, calificacion: cal, color: color,
        es_real: esLoteReal, rango_temp: rango.toFixed(1),
        temp_esperada_min: tempEsperadaMin, temp_esperada_max: tempEsperadaMax,
        temp_ideal_min: tempIdealMin, temp_ideal_max: tempIdealMax,
        temp_aceptable_min: tempAceptableMin, temp_aceptable_max: tempAceptableMax,
        temp_alto_max: tempAltoMax,
        alcanza_ideal_teorico: alcanzaIdealTeorico
    };
}

