        });
    }
    if (loteMejorAnalisis.puntos_ph >= 22) {
        fortalezas.push({
            texto: 'Acidificación adecuada con pH final ' + loteMejorDatos.ph_final + ' en el rango óptimo 4.5–5.5, evidencia de la correcta actividad de las bacterias acéticas.',
