            texto: 'Variación térmica amplia de ' + lotePeorAnalisis.rango_temp + '°C, indicando control deficiente de la temperatura entre zonas del fermentador.',
            base: 'Estabilidad Térmica Lote ' + lotePeorObj + ': ' + lotePeorAnalisis.puntos_est + '/25 puntos.'
        });
        accionesTecnicas.push({
            texto: 'Implementar protocolo de volteos sistemáticos cada 24–48 horas en el Lote ' + lotePeorObj + ' para uniformar la temperatura del lote.',
            base: 'Variación térmica de ' + lotePeorAnalisis.rango_temp + '°C en Lote ' + lotePeorObj + '.'
        });
    }

    if (lotePeorAnalisis.puntos_ph < 22) {
        const phPeor = parseFloat(lotePeorDatos.ph_final);
        if (phPeor < 4.5) {
            debilidades.push({
                texto: 'pH final bajo de ' + lotePeorDatos.ph_final + ' indica sobre-fermentación y exceso de ácido acético producido por las bacterias acéticas.',
