    // Estrategia ACTIVA: aporte de calor externo controlado
    accionesTecnicas.push({
        texto: 'Estrategia activa: implementar cámara climatizada con control de temperatura, lámparas infrarrojas o mantas térmicas para aportar calor externo controlado y mantener el lote en el rango ideal 45–50°C durante la fase acética en escala experimental.',
        base: 'Aporte térmico externo para acercarse al ideal teórico en escala experimental sin requerir masa industrial.'
    });
}

// === CONCLUSIÓN GENERAL ===
let recomendacionGeneral = '';
if (Math.abs(dif) <= 5) {
    recomendacionGeneral = 'Ambos lotes presentan calidad equivalente (' + analisisA.puntaje + ' y ' + analisisB.puntaje + ' puntos). Las condiciones de operación de ambos son replicables. Se recomienda documentar las variables ambientales para identificar factores diferenciales sutiles en próximos lotes.';
} else {
    recomendacionGeneral = 'El Lote ' + loteMejorObj + ' supera al Lote ' + lotePeorObj + ' por ' + Math.abs(dif) + ' puntos (' + loteMejorAnalisis.puntaje + ' vs ' + lotePeorAnalisis.puntaje + '). Se recomienda adoptar las condiciones operativas del Lote ' + loteMejorObj + ' como referencia para próximos procesos.';
}

// === OBSERVACIONES (clarificando ideal teórico vs esperado) ===
const observaciones = [];

// Observación 1: si los lotes son de DISTINTA escala
if (analisisA.es_real !== analisisB.es_real) {
    observaciones.push({
        texto: 'Los lotes pertenecen a escalas operativas distintas. El IDEAL TEÓRICO del cacao es 45–50°C en fase acética (donde el ácido acético inhibe el embrión y libera precursores aromáticos). En escala experimental (~20 kg) la disipación impide alcanzar este ideal y se considera ESPERADO un rango de 32–40°C.',
        base: 'Lote A: ' + (analisisA.es_real ? 'Experimental' : 'Comercial') + ' | Lote B: ' + (analisisB.es_real ? 'Experimental' : 'Comercial') + '.'
    });
}

// Observación 2: si Lote A es experimental y NO alcanzó ideal teórico
if (analisisA.es_real && !analisisA.alcanza_ideal_teorico) {
    observaciones.push({
        texto: 'Lote A registró ' + datosA.temp_max + '°C (esperado en escala experimental), pero NO alcanzó el ideal teórico de 45–50°C donde ocurre la fase acética completa. Para acercarse al ideal en próximas réplicas existen dos estrategias: pasiva (aumentar masa, mejor aislamiento, doble cobertura) o activa (cámara climatizada, lámparas IR, mantas térmicas con control de temperatura).',
        base: 'Temperatura Lote A: ' + datosA.temp_max + '°C vs ideal teórico 45–50°C.'
    });
}

// Observación 3: si Lote B es experimental y NO alcanzó ideal teórico
if (analisisB.es_real && !analisisB.alcanza_ideal_teorico) {
    observaciones.push({
        texto: 'Lote B registró ' + datosB.temp_max + '°C (esperado en escala experimental), pero NO alcanzó el ideal teórico de 45–50°C donde ocurre la fase acética completa. Para acercarse al ideal en próximas réplicas existen dos estrategias: pasiva (aumentar masa, mejor aislamiento, doble cobertura) o activa (cámara climatizada, lámparas IR, mantas térmicas con control de temperatura).',
        base: 'Temperatura Lote B: ' + datosB.temp_max + '°C vs ideal teórico 45–50°C.'
    });
}

const payloadComparacion = {
    loteA: {
        lote_id: datosA.lote_id, puntaje: analisisA.puntaje,
        calificacion: analisisA.calificacion, color: analisisA.color,
        es_real: analisisA.es_real
    },
    loteB: {
        lote_id: datosB.lote_id, puntaje: analisisB.puntaje,
        calificacion: analisisB.calificacion, color: analisisB.color,
        es_real: analisisB.es_real
    },
    comparaciones: comparaciones,
    lote_mejor: loteMejor,
    recomendacion_general: recomendacionGeneral,
    fortalezas: fortalezas,
    debilidades: debilidades,
    acciones_tecnicas: accionesTecnicas,
    observaciones: observaciones
};

const msgLoteA = { payload: datosA };
const msgLoteB = { payload: datosB };
const msgIA = { payload: payloadComparacion };

return [msgLoteA, msgLoteB, msgIA];

if (msg.payload !== "connect" && msg.payload !== "change") {
    return null;
}
const perfil = global.get("perfil_activo");
msg.payload = perfil || "";
return msg;

if (msg.payload === "volver_admin") {
    return { payload: { tab: "Admin - Inicio" } };
}
return null;

const datos = msg.payload;

if (!datos || !datos.loteA || !datos.loteB) {
    return null;
}

// Guardar los datos completos para el procesamiento posterior
flow.set("analisis_reglas", datos);

// Extraer datos en lenguaje natural (más fácil para el LLM que JSON crudo)
const escalaA = datos.loteA.es_real ? "experimental (~20 kg)" : "comercial (>100 kg)";
const escalaB = datos.loteB.es_real ? "experimental (~20 kg)" : "comercial (>100 kg)";

// Construir tabla resumida de criterios
const criteriosTexto = datos.comparaciones.map(function(c) {
    return "- " + c.nombre + ": Lote A = " + c.valorA + " (" + c.puntosA + "/25), Lote B = " + c.valorB + " (" + c.puntosB + "/25). Mejor: " + c.ganador.etiqueta;
}).join("\n");

const prompt = "Eres un ingeniero agroindustrial experto en fermentación de cacao nacional ecuatoriano. Redacta UNA SOLA conclusión técnica comparativa para los siguientes dos lotes.\n\n" +
    "CONTEXTO TÉCNICO:\n" +
    "- Fermentación óptima: 5-7 días, pH final 4.5-5.5\n" +
    "- Temperatura comercial: 45-50°C / experimental: 32-40°C\n" +
    "- Fases: anaerobia (levaduras), acética (bacterias acéticas), descenso\n\n" +
    "DATOS DE LOS LOTES:\n" +
    "Lote A: escala " + escalaA + ", evaluación " + datos.loteA.calificacion + " (" + datos.loteA.puntaje + "/100)\n" +
    "Lote B: escala " + escalaB + ", evaluación " + datos.loteB.calificacion + " (" + datos.loteB.puntaje + "/100)\n\n" +
    "CRITERIOS:\n" + criteriosTexto + "\n\n" +
    "RESULTADO: " + datos.lote_mejor + "\n\n" +
    "REGLAS ESTRICTAS:\n" +
    "1. Redacta UNA SOLA conclusión técnica de 3-5 oraciones (máximo 80 palabras)\n" +
    "2. Mantén los números exactos (°C, días, puntos, pH)\n" +
    "3. Menciona el lote ganador y por qué (qué criterio decidió la diferencia)\n" +
    "4. Estilo profesional industrial, sin saludos ni introducciones\n" +
    "5. Habla SOLO de: temperatura, pH, duración, volteos, hojas de plátano, mucílago, bacterias acéticas, levaduras, fermentación, embrión, grano\n" +
    "6. PROHIBIDO usar: sangre, salud, médico, dureza, infección, paciente, dosis\n" +
    "7. PROHIBIDO usar asteriscos, guiones, listas, numeración\n" +
    "8. Si la diferencia es <5 puntos, indica que ambos lotes son equivalentes\n\n" +
    "EJEMPLO DE BUENA CONCLUSIÓN:\n" +
    "El Lote A presenta mejor desempeño global (89 vs 67 puntos), principalmente por su control térmico superior (40.8°C dentro del rango óptimo experimental) y menor variación (12.3°C). El Lote B muestra picos térmicos excesivos de 56.9°C que comprometen el embrión. Se recomienda replicar las condiciones del Lote A en próximos procesos.\n\n" +
    "GENERA AHORA LA CONCLUSIÓN (solo el texto, sin encabezados ni etiquetas):";

msg.payload = {
    model: "qwen2.5:1.5b",
    prompt: prompt,
    stream: false,
    options: {
        temperature: 0.4,
        num_predict: 250,
        top_p: 0.85,
        stop: ["\n\n\n", "EJEMPLO", "REGLAS", "INSTRUC", "AHORA", "GENERA"]
    }
};

msg.url = "http://localhost:11434/api/generate";
msg.method = "POST";
msg.headers = { "Content-Type": "application/json" };


return msg;

// Recuperar el análisis base (con todos los datos de loteA, loteB, comparaciones, etc.)
const base = flow.get("analisis_reglas");

if (!base) {

    return null;
}

let respuesta = "";

// Normalizar respuesta de Ollama
if (msg.statusCode === 200 && msg.payload) {
    if (typeof msg.payload === "string") {
        respuesta = msg.payload;
    } else if (msg.payload.response) {
        respuesta = msg.payload.response;
    } else if (msg.payload.result) {
        respuesta = msg.payload.result;
    }
}

respuesta = (respuesta || "").trim();

// FALLBACK si Ollama no respondió bien
if (!respuesta || respuesta.length < 20) {
    base.fuente_recomendaciones = "Sistema base";
    // base.recomendacion_general ya existe de las reglas, no se modifica
    return { payload: base };
}

// Limpiar respuesta de markdown y caracteres raros
respuesta = respuesta
    .replace(/\*\*/g, "")
    .replace(/\*/g, "")
    .replace(/^["']|["']$/g, "")
    .trim();

// Filtro de palabras prohibidas (anti-alucinación)
const palabrasProhibidas = ["sangre", "sanguín", "dureza", "médic", "salud", "infecci", "paciente", "dosis", "medicament"];
const respuestaLower = respuesta.toLowerCase();
const tieneInvalida = palabrasProhibidas.some(function(p) { return respuestaLower.includes(p); });

if (tieneInvalida) {
    base.fuente_recomendaciones = "Sistema base";
    return { payload: base };
}

// ✅ ÉXITO: REEMPLAZAR la conclusión por la del LLM (nombres CORRECTOS para el template)
base.recomendacion_general = respuesta;
base.fuente_recomendaciones = "Análisis local Qwen 2.5";

return { payload: base };
